mapper.select:
select di.id as instanceId, di.template_id as templateId, di.aircraft_id as aircraftId, di.current_version_id as currentVersionId, di.current_version_no as currentVersionNo, di.instance_label as instanceLabel, di.status as instanceStatus, di.updated_at as instanceUpdatedAt, pa.tail_number as tailNumber, pa.msn, pa.registration_number as registrationNumber, pa.aircraft_type as aircraftType, pa.variant, pa.engine_type as engineType, pa.manufacturer, pa.delivery_date as deliveryDate, pa.operational_status as operationalStatus, pa.total_fh as totalFh, pa.total_fc as totalFc, pa.current_operator as currentOperator, am.model_code as modelCode, am.name as modelName, dt.template_code as templateCode, dt.template_version as templateVersion, dt.name as templateName from t1_dossier_instance di left join t1_physical_aircraft pa on pa.id = di.aircraft_id left join t1_ac_model am on am.id = pa.model_id left join t1_dossier_template dt on dt.id = di.template_id
di.deleted_at is null
and di.id = #{instanceId}
and di.aircraft_id = #{aircraftId}
order by case when pa.tail_number = 'B-1234' then 0 else 1 end, case when di.status in ('ready','published') then 0 else 1 end, case when dt.status = 'active' then 0 else 1 end, case when dt.is_default = 1 then 0 else 1 end, di.updated_at desc limit 1

select dv.id as versionId, dv.dossier_instance_id as instanceId, dv.template_id as templateId, dv.template_code as templateCode, dv.template_version as templateVersion, dv.version_no as versionNo, dv.version_label as versionLabel, dv.major_version_no as majorVersionNo, dv.minor_version_no as minorVersionNo, dv.version_level as versionLevel, dv.previous_version_id as previousVersionId, dv.generation_job_id as generationJobId, dv.data_snapshot_id as dataSnapshotId, dv.version_reason as versionReason, dv.is_current as isCurrent, dv.change_summary as changeSummary, cast(dv.template_snapshot_json as char) as templateSnapshotJson, cast(dv.content_summary_json as char) as contentSummaryJson, cast(dv.generation_params_json as char) as generationParamsJson, dv.created_by as createdBy, dv.created_at as createdAt, dv.published_at as publishedAt, gj.job_code as jobCode, gj.job_status as jobStatus, gj.progress_percent as progressPercent, cast(gj.output_json as char) as outputJson, ds.snapshot_code as snapshotCode from t1_dossier_version dv left join t1_generation_job gj on gj.id = dv.generation_job_id left join t1_data_snapshot ds on ds.id = dv.data_snapshot_id where dv.dossier_instance_id = #{instanceId}
and dv.id = #{versionId}
order by case when dv.is_current = 1 then 0 else 1 end, dv.version_no desc limit 1

select id as contentItemId, structure_node_id as structureNodeId, item_code as itemCode, item_name as itemName, item_type as itemType, lifecycle_stage as lifecycleStage, aircraft_id as aircraftId, bom_node_id as bomNodeId, part_instance_id as partInstanceId, is_key_part as isKeyPart, supply_mode as supplyMode, source_system as sourceSystem, source_table as sourceTable, source_record_id as sourceRecordId, source_record_key as sourceRecordKey, item_status as itemStatus, required_flag as requiredFlag, included_flag as includedFlag, completeness_status as completenessStatus, content_summary as contentSummary, file_storage_key as fileStorageKey, cast(source_trace_json as char) as sourceTraceJson, cast(attrs_json as char) as attrsJson, created_at as createdAt from t1_dossier_content_item where dossier_version_id = #{versionId}
and bom_node_id = #{bomNodeId}
order by sort_order, item_code

select fr.id as documentEntryId, fr.file_id as fileAssetId, fr.category_id as categoryId, fr.relation_type as relationType, fr.target_type as targetType, fr.target_id as targetId, fr.target_code as targetCode, fr.target_name as targetName, fr.dossier_instance_id as instanceId, fr.dossier_version_id as versionId, fr.structure_node_id as structureNodeId, fr.aircraft_id as aircraftId, fr.bom_node_id as bomNodeId, fr.part_number as partNumber, fr.part_instance_id as partInstanceId, fr.object_level as objectLevel, fr.lifecycle_stage as lifecycleStage, fr.business_domain as businessDomain, fr.is_primary as isPrimary, fr.is_current as isCurrent, fa.file_code as fileCode, fa.asset_kind as assetKind, coalesce(fa.business_no, fr.target_code, fr.source_record_key) as docNo, fa.business_no as businessNo, fa.business_type as businessType, fa.business_title as businessTitle, fa.revision, fa.file_status as fileStatus, fa.original_file_name as originalFileName, fa.display_name as displayName, coalesce(fa.business_title, fa.display_name) as title, fa.file_ext as fileExt, fa.mime_type as mimeType, fa.storage_type as storageType, fa.storage_bucket as storageBucket, fa.storage_key as storageKey, fa.storage_path as storagePath, fa.access_url as accessUrl, fa.preview_storage_key as previewStorageKey, coalesce(fa.storage_key, fa.storage_path, fa.access_url) as fileStorageKey, fa.file_size as fileSize, fa.hash_algorithm as hashAlgorithm, fa.file_hash as fileHash, fa.issue_date as issueDate, fa.effective_date as effectiveDate, fa.expiry_date as expiryDate, fa.issued_by as issuedBy, fa.security_level as securityLevel, fa.is_latest as isLatest, coalesce(fr.source_system, fa.source_system) as sourceSystem, 't1_file_relation' as sourceTable, coalesce(fr.source_record_id, fa.source_record_id) as sourceRecordId, coalesce(fr.source_record_key, fa.source_record_key) as sourceRecordKey, fr.relation_status as documentStatus, fr.completeness_status as completenessStatus, fr.required_flag as requiredFlag, fr.included_flag as includedFlag, cast(fr.source_trace_json as char) as sourceTraceJson, cast(fr.business_meta_json as char) as attrsJson, fr.created_at as createdAt from t1_file_relation fr inner join t1_file_asset fa on fa.id = fr.file_id where fr.dossier_version_id = #{versionId} and fr.relation_status != 'deleted'
and fr.structure_node_id = #{structureNodeId}
order by fr.required_flag desc, title

select id as operationLogId, operation_type as operationType, operation_name as operationName, operation_status as operationStatus, business_subject_type as businessSubjectType, business_subject_id as businessSubjectId, operator_name as operatorName, result_message as resultMessage, operated_at as operatedAt, cast(detail_json as char) as detailJson from t1_dossier_operation_log where dossier_instance_id = #{instanceId}
and (dossier_version_id = #{versionId} or dossier_version_id is null)
order by operated_at desc limit 20
